   121→  function calcularKPIs(mes, ano) {
   122→    var lista    = transacoesDo(mes, ano);
   123→    var receita  = lista.filter(function(t){ return t.tipo==='Entrada'; }).reduce(function(s,t){ return s+t.valor; },0);
