   138→      var v = raixoSomaLinha(RAIOX.variaveis, m);
   139→      var s = r - f - v;
   140→      acum += s;
   141→      totais.receitas.push(r);
   142→      totais.fixas.push(f);
   143→      totais.variaveis.push(v);
   144→      totais.saldo.push(s);
   145→      totais.acumulado.push(acum);
   146→    }
   147→    return totais;
   148→  }
