   614→  function calcularMilhao() {
   615→    var aporte     = parseFloat(document.getElementById('mil-aporte')    ?.value) || 0;
   616→    var patrimonio = parseFloat(document.getElementById('mil-patrimonio') ?.value) || 0;
   617→    var taxa       = (parseFloat(document.getElementById('mil-taxa')      ?.value) || 1) / 100;
   618→    var meta       = metaMilhao;
   619→
   620→    // Data de nascimento: 05/04/2001
   621→    var nascimento = new Date(2001, 3, 5); // April 5, 2001
   622→
   623→    if (aporte <= 0 && patrimonio < meta) {
   624→      return;
   625→    }
   626→
   627→    // Cálculo iterativo: FV = PV*(1+r)^n + PMT*((1+r)^n - 1)/r
   628→    var n = 0, fv = patrimonio;
   629→    var MAX = 12000; // 1000 anos max
   630→    while (fv < meta && n < MAX) {
   631→      fv = fv * (1 + taxa) + aporte;
   632→      n++;
   633→    }
   634→
   635→    if (n >= MAX) {
   636→      // Nunca vai atingir
   637→      var elData  = document.getElementById('mil-data');
   638→      var elIdade = document.getElementById('mil-idade');
   639→      if (elData)  elData.textContent  = 'Nunca com este aporte';
   640→      if (elIdade) elIdade.textContent = 'Aumente o aporte mensal';
   641→      return;
   642→    }
   643→
   644→    // Data alvo
   645→    var hoje       = new Date();
   646→    var dataAlvo   = new Date(hoje);
   647→    dataAlvo.setMonth(dataAlvo.getMonth() + n);
   648→
   649→    // Idade na data alvo
   650→    var diffMs    = dataAlvo - nascimento;
   651→    var idadeTotal = diffMs / (1000 * 60 * 60 * 24 * 365.25);
   652→    var anos      = Math.floor(idadeTotal);
   653→    var mesesR    = Math.floor((idadeTotal - anos) * 12);
   654→
   655→    // Total aportado vs juros
   656→    var totalAportado = aporte * n + patrimonio;
   657→    var jurosGerados  = fv - totalAportado;
   658→
   659→    // Progresso atual
   660→    var pct = Math.min((patrimonio / meta) * 100, 100);
   661→
   662→    // Mostrar display
   663→    var idle    = document.getElementById('mil-idle');
   664→    var display = document.getElementById('mil-display');
   665→    if (idle)    idle.classList.add('hidden');
   666→    if (display) display.classList.remove('hidden');
   667→
   668→    // Preencher valores
   669→    var elData  = document.getElementById('mil-data');
   670→    var elIdade = document.getElementById('mil-idade');
   671→    var elMeses = document.getElementById('mil-meses');
   672→    var elTotalA= document.getElementById('mil-total-aportado');
   673→    var elJuros = document.getElementById('mil-juros');
   674→    var elFill  = document.getElementById('mil-prog-fill');
   675→    var elGlow  = document.getElementById('mil-prog-glow');
   676→    var elPct   = document.getElementById('mil-prog-pct');
   677→    var elAtual = document.getElementById('mil-prog-atual');
   678→    var elMeta  = document.getElementById('mil-prog-meta');
   679→    var badge   = document.getElementById('mil-meta-badge');
   680→
   681→    var meses_str = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];
