  function raixoTotaisMensais() {
    var totais = { receitas:[], fixas:[], variaveis:[], saldo:[], acumulado:[] };
    var acum = 0;
    for (var m = 0; m < 12; m++) {
      var r = raixoSomaLinha(RAIOX.entradas, m);
      var f = raixoSomaLinha(RAIOX.fixas, m);
      var v = raixoSomaLinha(RAIOX.variaveis, m);
      var s = r - f - v;
      acum += s;
      totais.receitas.push(r);
      totais.fixas.push(f);
      totais.variaveis.push(v);
      totais.saldo.push(s);
      totais.acumulado.push(acum);
    }
    return totais;
  }

  // ── INICIALIZAÇÃO ──────────────────────────────────────────────────────────
  function initFinanceiro() {
    // Tabs internos
    document.querySelectorAll('.fin-tab-btn').forEach(function(btn) {
      btn.addEventListener('click', function() {
        var tab = this.dataset.tab;
        document.querySelectorAll('.fin-tab-btn').forEach(function(b){ b.classList.remove('active'); });
        document.querySelectorAll('.fin-tab-pane').forEach(function(p){ p.classList.remove('active'); });
        this.classList.add('active');
        var pane = document.getElementById('fin-pane-' + tab);
        if (pane) pane.classList.add('active');
        if (tab === 'visao-geral')  { renderCharts(); renderRaioX(); }
        if (tab === 'projecoes')    { renderGraficoLinha(); atualizarProjecoes(); }
        if (tab === 'milhao')       { initProjetoMilhao(); }
      });
    });

    // IA
    var btnIA = document.getElementById('fin-ai-btn');
    if (btnIA) btnIA.addEventListener('click', gerarAnaliseIA);

    // Lançamentos
    var btnAdd = document.getElementById('fin-add-btn');
    if (btnAdd) btnAdd.addEventListener('click', adicionarLancamento);

    var prevBtn = document.getElementById('fin-mes-prev');
    var nextBtn = document.getElementById('fin-mes-next');
    if (prevBtn) prevBtn.addEventListener('click', function(){ navegarMes(-1); });
    if (nextBtn) nextBtn.addEventListener('click', function(){ navegarMes(1); });

    var dataInput = document.getElementById('fin-data');
    if (dataInput) dataInput.value = new Date().toISOString().split('T')[0];

    // Filtro de mês na Visão Geral
    var selectMes = document.getElementById('fin-visao-mes');
    if (selectMes) {
      selectMes.value = String(mesSelecionado);
      selectMes.addEventListener('change', function () {
        var novoMes = parseInt(this.value, 10) || mesSelecionado;
        mesSelecionado = novoMes;
        anoSelecionado = 2026;
        atualizarTudo();
        renderRaioX();
        // Sincroniza label de lançamentos
        atualizarMesLabel();
      });
    }

    atualizarTudo();
    renderRaioX();
  }

  function atualizarTudo() {
    atualizarKPIs();
    atualizarTabela();
    atualizarProjecoes();
    atualizarMesLabel();
    renderCharts();
  }

  // ── KPIs ───────────────────────────────────────────────────────────────────
  function atualizarKPIs() {
    var kpis = calcularKPIs(mesSelecionado, anoSelecionado);
    var acumulado = 0;
    for (var m = 1; m <= mesSelecionado; m++) {
      acumulado += calcularKPIs(m, anoSelecionado).saldo;
    }
    var elR = document.getElementById('fin-kpi-receita');
    var elD = document.getElementById('fin-kpi-despesas');
    var elS = document.getElementById('fin-kpi-saldo');
    var elP = document.getElementById('fin-kpi-projecao');
    var elM = document.getElementById('fin-kpi-receita-mes');
    if (elR) elR.textContent = fmt(kpis.receita);
    if (elD) elD.textContent = fmt(kpis.despesas);
    if (elM) elM.textContent = mesLabel(mesSelecionado, anoSelecionado);
    if (elS) {
      elS.textContent = (kpis.saldo < 0 ? '-' : '') + fmt(kpis.saldo);
      elS.className = 'fin-kpi-value ' + (kpis.saldo >= 0 ? 'fin-val-positive' : 'fin-val-negative');
    }
    if (elP) {
      elP.textContent = (acumulado < 0 ? '-' : '') + fmt(acumulado);
      elP.className = 'fin-kpi-value ' + (acumulado >= 0 ? 'fin-val-positive' : 'fin-val-negative');
    }
  }

  // ── RAIO-X TABLE ───────────────────────────────────────────────────────────
  function renderRaioX() {
    var table = document.getElementById('fin-raiox-table');
    if (!table) return;

    var totais = raixoTotaisMensais();
    var html = '';

    // Cabeçalho
    html += '<thead><tr><th class="fin-rx-th-label">Item</th>';
    MESES_LABEL.forEach(function(m, i) {
      var isPast = (i + 1) < mesSelecionado || (i + 1 === mesSelecionado);
      html += '<th class="fin-rx-th-mes' + (isPast ? ' fin-rx-past' : ' fin-rx-future') + '">' + m + '</th>';
    });
    html += '<th class="fin-rx-th-anual">Total 2026</th></tr></thead>';

    html += '<tbody>';

    // ── ENTRADAS
    html += '<tr class="fin-rx-section-header"><td colspan="14">↑ RECEITAS</td></tr>';
    RAIOX.entradas.forEach(function(item) {
      html += renderRaioXLinha(item, 'entrada');
    });
    html += renderRaioXTotalLinha('TOTAL RECEITAS', totais.receitas, 'fin-rx-total fin-rx-total-entrada');

    // ── DESPESAS FIXAS
    html += '<tr class="fin-rx-section-header fin-rx-sec-saida"><td colspan="14">↓ DESPESAS FIXAS</td></tr>';
    RAIOX.fixas.forEach(function(item) {
      html += renderRaioXLinha(item, 'fixa');
    });
    html += renderRaioXTotalLinha('TOTAL FIXAS', totais.fixas, 'fin-rx-total fin-rx-total-saida');

    // ── DESPESAS VARIÁVEIS
    html += '<tr class="fin-rx-section-header fin-rx-sec-var"><td colspan="14">↓ DESPESAS VARIÁVEIS</td></tr>';
    RAIOX.variaveis.forEach(function(item) {
      html += renderRaioXLinha(item, 'variavel');
    });
    html += renderRaioXTotalLinha('TOTAL VARIÁVEIS', totais.variaveis, 'fin-rx-total fin-rx-total-saida');

    // ── RESUMO
    html += '<tr class="fin-rx-section-header fin-rx-sec-resumo"><td colspan="14">◈ RESUMO</td></tr>';
    html += renderRaioXSaldoLinha('SALDO MENSAL', totais.saldo);
    html += renderRaioXAcumLinha('ACUMULADO', totais.acumulado);

    html += '</tbody>';
    table.innerHTML = html;
  }

  function renderRaioXLinha(item, tipo) {
    var total = item.v.reduce(function(s,v){ return s+v; }, 0);
    var cls   = tipo === 'entrada' ? 'fin-rx-entrada' : (tipo === 'fixa' ? 'fin-rx-fixa' : 'fin-rx-variavel');
    var html  = '<tr class="fin-rx-row ' + cls + '"><td class="fin-rx-nome">' + item.nome + '</td>';
    item.v.forEach(function(v, i) {
      var isPast = (i + 1) <= mesSelecionado;
      var cellCls = isPast ? '' : ' fin-rx-proj';
      html += '<td class="fin-rx-cell' + cellCls + '">' + (v > 0 ? fmtRx(v) : '<span class="fin-rx-zero">—</span>') + '</td>';
    });
    html += '<td class="fin-rx-anual">' + fmtRx(total) + '</td></tr>';
    return html;
  }

  function renderRaioXTotalLinha(label, arr, cls) {
    var total = arr.reduce(function(s,v){ return s+v; }, 0);
    var html  = '<tr class="fin-rx-total-row ' + cls + '"><td class="fin-rx-nome">' + label + '</td>';
    arr.forEach(function(v) {
      html += '<td class="fin-rx-total-cell">' + fmtRx(v) + '</td>';
    });
    html += '<td class="fin-rx-total-cell">' + fmtRx(total) + '</td></tr>';
    return html;
  }

  function renderRaioXSaldoLinha(label, arr) {
    var total = arr.reduce(function(s,v){ return s+v; }, 0);
    var html  = '<tr class="fin-rx-saldo-row"><td class="fin-rx-nome">' + label + '</td>';
    arr.forEach(function(v) {
      var cls = v >= 0 ? 'fin-rx-pos' : 'fin-rx-neg';
      html += '<td class="fin-rx-saldo-cell ' + cls + '">' + (v < 0 ? '-' : '+') + fmtRx(Math.abs(v)) + '</td>';
    });
    var tcls = total >= 0 ? 'fin-rx-pos' : 'fin-rx-neg';
    html += '<td class="fin-rx-saldo-cell ' + tcls + '">' + (total < 0 ? '-' : '+') + fmtRx(Math.abs(total)) + '</td></tr>';
    return html;
  }

  function renderRaioXAcumLinha(label, arr) {
    var html = '<tr class="fin-rx-acum-row"><td class="fin-rx-nome">' + label + '</td>';
    arr.forEach(function(v) {
      var cls = v >= 0 ? 'fin-rx-acum-pos' : 'fin-rx-acum-neg';
      html += '<td class="fin-rx-acum-cell ' + cls + '">' + fmtRx(v) + '</td>';
    });
    var last = arr[arr.length - 1];
    var tcls = last >= 0 ? 'fin-rx-acum-pos' : 'fin-rx-acum-neg';
    html += '<td class="fin-rx-acum-cell ' + tcls + '">—</td></tr>';
    return html;
  }

  function fmtRx(v) {
    return 'R$\u00a0' + Math.abs(v).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  }

