function sincronizarScrollTopo() {
  var scrollBot = document.getElementById('fin-raiox-scroll');
  var scrollTop = document.getElementById('fin-raiox-scroll-top');
  var inner     = document.getElementById('fin-raiox-scroll-top-inner');
  if (!scrollBot || !scrollTop || !inner) return;

  // Ajusta largura do inner para igualar largura real da tabela
  inner.style.width = scrollBot.scrollWidth + 'px';

  // Remove listeners antigos clonando os elementos
  var newTop = scrollTop.cloneNode(true);
  scrollTop.parentNode.replaceChild(newTop, scrollTop);
  var newBot = scrollBot.cloneNode(false);
  while (scrollBot.firstChild) newBot.appendChild(scrollBot.firstChild);
  scrollBot.parentNode.replaceChild(newBot, scrollBot);

  // Re-referencia após clone
  var sTop = document.getElementById('fin-raiox-scroll-top');
  var sBot = document.getElementById('fin-raiox-scroll');

  sTop.addEventListener('scroll', function() { sBot.scrollLeft = sTop.scrollLeft; });
  sBot.addEventListener('scroll', function() { sTop.scrollLeft = sBot.scrollLeft; });
}

