      var entrada = recorrentes.filter(function(t){ return t.tipo==='Entrada'; }).reduce(function(s,t){ return s+t.valor; },0);
      var saida   = recorrentes.filter(function(t){ return t.tipo==='Saída';   }).reduce(function(s,t){ return s+t.valor; },0);
      meses.push({ mes:mesProj, ano:anoProj, entrada:entrada, saida:saida, saldo:entrada-saida });
    }
    grid.innerHTML = meses.map(function(m) {
