/* ══════════════════════════════════════════════════════
   SITE ARCHITECT — Gerador de Landing Page
══════════════════════════════════════════════════════ */

.sa-layout {
  display: grid;
  grid-template-columns: 360px 1fr;
  height: 100vh;
  overflow: hidden;
}

.sa-sidebar {
  border-right: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  overflow-y: auto;
  scrollbar-width: thin;
  scrollbar-color: var(--border) transparent;
  background: rgba(5,8,16,.96);
}

.sa-header {
  display: flex;
  align-items: flex-start;
  gap: .9rem;
  padding: 1.5rem 1.5rem 1.25rem;
  border-bottom: 1px solid var(--border);
  background: rgba(0,229,255,.025);
  flex-shrink: 0;
}

.sa-header-icon {
  font-size: 1.6rem;
  color: var(--cyan);
  text-shadow: 0 0 14px var(--cyan-glow);
  margin-top: .1rem;
}

.sa-title {
  font-family: var(--ff-h);
  font-weight: 800;
  font-size: 1.1rem;
  letter-spacing: .1em;
  color: var(--white);
  text-transform: uppercase;
}

.sa-subtitle {
  font-size: .8rem;
  color: rgba(176,190,197,.55);
  margin-top: .3rem;
  line-height: 1.4;
}

.sa-form {
  padding: 1.2rem 1.5rem 1.5rem;
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.sa-group-label {
  font-family: var(--ff-h);
  font-size: .62rem;
  letter-spacing: .14em;
  text-transform: uppercase;
  color: var(--cyan);
  opacity: .8;
  padding-top: .5rem;
  border-top: 1px solid rgba(0,229,255,.1);
}

.sa-form > .sa-group-label:first-child {
  border-top: none;
  padding-top: 0;
}

.sa-field {
  display: flex;
  flex-direction: column;
  gap: .4rem;
}

.sa-label {
  font-size: .7rem;
  letter-spacing: .12em;
  text-transform: uppercase;
  color: rgba(176,190,197,.7);
}

.sa-input,
.sa-textarea {
  width: 100%;
  background: rgba(255,255,255,.03);
  border: 1px solid rgba(0,229,255,.18);
  border-radius: 8px;
  padding: .55rem .75rem;
  color: var(--white);
  font-family: var(--ff-b);
  font-size: .9rem;
  outline: none;
  transition: border-color .2s, box-shadow .2s;
}

.sa-input:focus,
.sa-textarea:focus {
  border-color: var(--cyan);
  box-shadow: 0 0 0 2px rgba(0,229,255,.12);
}

.sa-input::placeholder,
.sa-textarea::placeholder {
  color: rgba(176,190,197,.35);
}

.sa-textarea {
  resize: vertical;
  min-height: 70px;
}

.sa-hint {
  font-size: .75rem;
  color: rgba(176,190,197,.45);
}

.sa-upload-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0,1fr));
  gap: .8rem;
}

.sa-upload-card {
  display: flex;
  flex-direction: column;
  gap: .35rem;
}

.sa-dropzone {
  border: 1px dashed rgba(0,229,255,.2);
  border-radius: 10px;
  padding: .6rem;
  min-height: 80px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  background: rgba(255,255,255,.02);
  position: relative;
  overflow: hidden;
  transition: border-color .2s, background .2s;
}

.sa-dropzone:hover,
.sa-dropzone.sa-dragover {
  border-color: var(--cyan);
  background: rgba(0,229,255,.05);
}

.sa-file-input {
  position: absolute;
  inset: 0;
  opacity: 0;
  cursor: pointer;
}

.sa-drop-placeholder {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: .3rem;
  color: rgba(176,190,197,.5);
  font-size: .8rem;
  pointer-events: none;
}

.sa-drop-placeholder span {
  font-size: 1.2rem;
}

.sa-preview {
  width: 100%;
  border-radius: 8px;
  object-fit: cover;
}

.sa-preview-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0,1fr));
  gap: .3rem;
  width: 100%;
}

.sa-preview-grid img {
  width: 100%;
  height: 52px;
  object-fit: cover;
  border-radius: 6px;
}

.sa-actions {
  display: grid;
  grid-template-columns: minmax(0,1fr) auto;
  gap: .6rem;
  margin-top: .25rem;
}

.sa-btn-primary {
  height: 44px;
  border-radius: 10px;
  border: none;
  background: linear-gradient(135deg, #00e5ff 0%, #00b8d4 40%, #006dd9 100%);
  color: #020d18;
  font-family: var(--ff-b);
  font-size: .95rem;
  font-weight: 700;
  letter-spacing: .06em;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: .55rem;
  box-shadow: 0 0 22px rgba(0,229,255,.38), 0 4px 16px rgba(0,0,0,.45);
  transition: opacity .2s, transform .15s, box-shadow .2s;
}

.sa-btn-primary:hover {
  opacity: .95;
  transform: translateY(-1px);
  box-shadow: 0 0 30px rgba(0,229,255,.55), 0 6px 20px rgba(0,0,0,.45);
}

.sa-btn-primary:disabled {
  opacity: .45;
  cursor: not-allowed;
  box-shadow: none;
  transform: none;
}

.sa-btn-icon {
  font-size: 1rem;
}

.sa-btn-ghost {
  height: 44px;
