    var total = item.v.reduce(function(s,v){ return s+v; }, 0);
    var cls   = tipo === 'entrada' ? 'fin-rx-entrada' : (tipo === 'fixa' ? 'fin-rx-fixa' : 'fin-rx-variavel');
    var html  = '<tr class="fin-rx-row ' + cls + '">' +
      '<td class="fin-rx-nome">' +
        '<button class="fin-rx-del-btn" data-section="' + sectionKey + '" data-idx="' + itemIdx + '" title="Remover">✕</button>' +
        '<span class="fin-rx-nome-text fin-rx-editable-nome" data-section="' + sectionKey + '" data-idx="' + itemIdx + '">' + item.nome + '</span>' +
      '</td>';
    item.v.forEach(function(v, i) {
      var isPast = (i + 1) <= mesSelecionado;
      var cellCls = isPast ? '' : ' fin-rx-proj';
      html += '<td class="fin-rx-cell' + cellCls + ' fin-rx-editable-cell" data-section="' + sectionKey + '" data-idx="' + itemIdx + '" data-mes="' + i + '">' +
