            data: totais.receitas,
            borderColor: '#69f0ae',
            backgroundColor: 'rgba(105,240,174,0.06)',
            borderWidth: 2.5,
            pointRadius: 4,
            pointHoverRadius: 6,
            pointBackgroundColor: '#69f0ae',
            tension: 0.35,
            fill: false,
          },
          {
            label: 'Despesas',
            data: totais.fixas.map(function(f, i){ return f + totais.variaveis[i]; }),
            borderColor: '#ff5252',
            backgroundColor: 'rgba(255,82,82,0.06)',
            borderWidth: 2.5,
            pointRadius: 4,
            pointHoverRadius: 6,
            pointBackgroundColor: '#ff5252',
            tension: 0.35,
            fill: false,
          },
          {
            label: 'Acumulado',
            data: totais.acumulado,
            borderColor: '#00e5ff',
            backgroundColor: 'rgba(0,229,255,0.04)',
            borderWidth: 2,
            borderDash: [6, 4],
            pointRadius: 4,
            pointHoverRadius: 6,
            pointBackgroundColor: '#00e5ff',
            pointStyle: 'rectRot',
