              label: function(ctx) {
                return ' ' + ctx.dataset.label + ': R$ ' + ctx.raw.toLocaleString('pt-BR', {minimumFractionDigits:2});
              }
            }
          }
        },
        scales: {
          x: { ticks: { color: '#b0bec5', font: { family: 'Rajdhani' } }, grid: { color: 'rgba(0,229,255,0.05)' } },
          y: {
            ticks: { color: '#b0bec5', font: { family: 'Rajdhani' }, callback: function(v){ return 'R$ ' + (v/1000).toFixed(1)+'K'; } },
            grid: { color: 'rgba(0,229,255,0.07)' }
          }
