  var RAIOX = carregarRaioX() || JSON.parse(JSON.stringify(RAIOX_PADRAO));

  var MESES_LABEL = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];

  // ── ESTADO ─────────────────────────────────────────────────────────────────
  var mesSelecionado = 2;
