/* ──────────────────────────────────────────────────────
   Jake OS — Módulo Financeiro Pessoal 2.0
   Dark Mode · Glassmorphism · Cyan Neon
────────────────────────────────────────────────────── */

(function () {

  // ── DADOS REAIS 2026 (Transações) ──────────────────────────────────────────
  var _nextId = 100;
  var TRANSACOES = [
    // ── JANEIRO 2026 ──
    { id:1,  descricao:'Dentto',              valor:4300.00,  tipo:'Entrada', categoria:'Fixa',     recorrente:true,  data:'2026-01-05' },
    { id:2,  descricao:'Pedras Carula',       valor:800.00,   tipo:'Entrada', categoria:'Fixa',     recorrente:true,  data:'2026-01-05' },
    { id:3,  descricao:'Suprema Metal',       valor:800.00,   tipo:'Entrada', categoria:'Fixa',     recorrente:true,  data:'2026-01-05' },
    { id:4,  descricao:'Piloti',              valor:3250.00,  tipo:'Entrada', categoria:'Fixa',     recorrente:true,  data:'2026-01-05' },
    { id:5,  descricao:'Diversos',            valor:1100.00,  tipo:'Entrada', categoria:'Variável', recorrente:false, data:'2026-01-10' },
