  // ── CHARTS (KPI page) ──────────────────────────────────────────────────────
  function renderCharts() {
    if (typeof Chart === 'undefined') return;
    renderBarras();
    renderDonut();
  }

  function renderBarras() {
    var canvas = document.getElementById('fin-chart-barras');
    if (!canvas) return;
    var labels = [], receitas = [], despesas = [];
    for (var i = 3; i >= 0; i--) {
      var m = mesSelecionado - i, a = anoSelecionado;
      if (m <= 0) { m += 12; a--; }
      var kpi = calcularKPIs(m, a);
      labels.push(mesLabel(m, a).split(' ')[0].substring(0,3));
      receitas.push(parseFloat(kpi.receita.toFixed(2)));
      despesas.push(parseFloat(kpi.despesas.toFixed(2)));
    }
    if (chartBarras) chartBarras.destroy();
    chartBarras = new Chart(canvas, {
      type: 'bar',
      data: {
        labels: labels,
        datasets: [
          { label: 'Receitas', data: receitas, backgroundColor: 'rgba(105,240,174,0.7)', borderColor: '#69f0ae', borderWidth: 1.5, borderRadius: 6 },
          { label: 'Despesas', data: despesas, backgroundColor: 'rgba(255,82,82,0.6)',   borderColor: '#ff5252', borderWidth: 1.5, borderRadius: 6 },
        ]
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        plugins: {
          legend: { labels: { color: '#b0bec5', font: { family: 'Rajdhani', size: 13 } } },
          tooltip: { callbacks: { label: function(ctx){ return ' '+ctx.dataset.label+': R$ '+ctx.raw.toLocaleString('pt-BR',{minimumFractionDigits:2}); } } }
        },
        scales: {
          x: { ticks: { color: '#b0bec5', font: { family: 'Rajdhani' } }, grid: { color: 'rgba(0,229,255,0.05)' } },
          y: { ticks: { color: '#b0bec5', font: { family: 'Rajdhani' }, callback: function(v){ return 'R$ '+v.toLocaleString('pt-BR'); } }, grid: { color: 'rgba(0,229,255,0.08)' } }
        }
      }
    });
  }

  function renderDonut() {
    var canvas = document.getElementById('fin-chart-donut');
    if (!canvas) return;
    var lista  = transacoesDo(mesSelecionado, anoSelecionado).filter(function(t){ return t.tipo==='Saída'; });
    var grupos = {};
    lista.forEach(function(t) {
      var k = t.descricao.length > 18 ? t.descricao.substring(0,18)+'…' : t.descricao;
      grupos[k] = (grupos[k] || 0) + t.valor;
    });
    var entries = Object.entries(grupos).sort(function(a,b){ return b[1]-a[1]; });
    var top = entries.slice(0,8);
    var outros = entries.slice(8).reduce(function(s,e){ return s+e[1]; }, 0);
    if (outros > 0) top.push(['Outros', outros]);
    var colors = ['#00e5ff','#69f0ae','#ff5252','#ffd740','#7c4dff','#ff6e40','#40c4ff','#e040fb','#b0bec5'];
    if (chartDonut) chartDonut.destroy();
    chartDonut = new Chart(canvas, {
      type: 'doughnut',
      data: {
        labels: top.map(function(e){ return e[0]; }),
        datasets: [{ data: top.map(function(e){ return parseFloat(e[1].toFixed(2)); }), backgroundColor: colors.slice(0,top.length).map(function(c){ return c+'cc'; }), borderColor: colors.slice(0,top.length), borderWidth: 1.5, hoverOffset: 8 }]
      },
      options: {
        responsive: true, maintainAspectRatio: false, cutout: '65%',
        plugins: {
          legend: { position: 'right', labels: { color: '#b0bec5', font: { family: 'Rajdhani', size: 12 }, padding: 12, boxWidth: 14 } },
          tooltip: { callbacks: { label: function(ctx){ var total=ctx.dataset.data.reduce(function(s,v){return s+v;},0); var pct=((ctx.raw/total)*100).toFixed(1); return ' R$ '+ctx.raw.toLocaleString('pt-BR',{minimumFractionDigits:2})+' ('+pct+'%)'; } } }
        }
      }
    });
  }

  // ── TABELA ─────────────────────────────────────────────────────────────────
  function atualizarTabela() {
    var tbody = document.getElementById('fin-tbody');
    if (!tbody) return;
    var lista = transacoesDo(mesSelecionado, anoSelecionado);
    lista.sort(function(a,b){ return a.data.localeCompare(b.data); });
    if (lista.length === 0) { tbody.innerHTML = '<tr><td colspan="6" class="fin-empty-row">Nenhuma movimentação neste mês</td></tr>'; return; }
    tbody.innerHTML = lista.map(function(t) {
      var dataFmt  = t.data.split('-').reverse().join('/');
      var recTag   = t.recorrente ? '<span class="fin-badge fin-badge-rec">↺</span>' : '';
      var catTag   = '<span class="fin-badge fin-badge-' + (t.categoria==='Fixa'?'fix':'var') + '">' + t.categoria + '</span>';
      var tpClass  = t.tipo==='Entrada' ? 'fin-val-positive' : 'fin-val-negative';
      var sinal    = t.tipo==='Entrada' ? '+' : '-';
      return '<tr>' +
        '<td class="fin-td-data">' + dataFmt + '</td>' +
        '<td class="fin-td-desc">' + t.descricao + ' ' + recTag + '</td>' +
        '<td>' + catTag + '</td>' +
        '<td><span class="fin-tipo-badge fin-tipo-' + (t.tipo==='Entrada'?'entrada':'saida') + '">' + t.tipo + '</span></td>' +
        '<td class="' + tpClass + ' fin-td-valor">' + sinal + ' ' + fmt(t.valor) + '</td>' +
        '<td><button class="fin-del-btn" data-id="' + t.id + '">✕</button></td>' +
      '</tr>';
    }).join('');
    tbody.querySelectorAll('.fin-del-btn').forEach(function(btn) {
      btn.addEventListener('click', function() {
        var id = parseInt(this.dataset.id);
        TRANSACOES = TRANSACOES.filter(function(t){ return t.id !== id; });
        atualizarTudo();
      });
    });
  }

  // ── PROJEÇÕES (3 meses) ────────────────────────────────────────────────────
  function atualizarProjecoes() {
    var grid = document.getElementById('fin-proj-grid');
    if (!grid) return;
    var recorrentes = TRANSACOES.filter(function(t) {
      var y = String(anoSelecionado), m = String(mesSelecionado).padStart(2,'0');
      return t.data.startsWith(y+'-'+m) && t.recorrente;
    });
    var meses = [];
    for (var i = 1; i <= 3; i++) {
      var mesProj = mesSelecionado + i, anoProj = anoSelecionado;
      if (mesProj > 12) { mesProj -= 12; anoProj++; }
      var entrada = recorrentes.filter(function(t){ return t.tipo==='Entrada'; }).reduce(function(s,t){ return s+t.valor; },0);
      var saida   = recorrentes.filter(function(t){ return t.tipo==='Saída';   }).reduce(function(s,t){ return s+t.valor; },0);
      meses.push({ mes:mesProj, ano:anoProj, entrada:entrada, saida:saida, saldo:entrada-saida });
    }
    grid.innerHTML = meses.map(function(m) {
      var cls   = m.saldo >= 0 ? 'fin-proj-positive' : 'fin-proj-negative';
      var sinal = m.saldo >= 0 ? '+' : '-';
      return '<div class="fin-proj-card">' +
        '<div class="fin-proj-mes">' + mesLabel(m.mes, m.ano) + '</div>' +
        '<div class="fin-proj-row"><span>Ganhos Fixos</span><span class="fin-val-positive">' + fmt(m.entrada) + '</span></div>' +
        '<div class="fin-proj-row"><span>Gastos Fixos</span><span class="fin-val-negative">-' + fmt(m.saida) + '</span></div>' +
        '<div class="fin-proj-divider"></div>' +
        '<div class="fin-proj-row fin-proj-saldo"><span>Saldo Projetado</span><span class="' + cls + '">' + sinal + ' ' + fmt(Math.abs(m.saldo)) + '</span></div>' +
      '</div>';
    }).join('');
  }

  // ── PROJETO 1 MILHÃO ──────────────────────────────────────────────────────
  var _milhaoInited = false;
  function initProjetoMilhao() {
    if (_milhaoInited) return;
    _milhaoInited = true;

    // Sugerir aporte = média do saldo mensal (positivo) dos dados disponíveis
    var totais = raixoTotaisMensais();
    var saldosPos = totais.saldo.filter(function(s){ return s > 0; });
    var mediaSaldo = saldosPos.length > 0
      ? Math.round(saldosPos.reduce(function(s,v){ return s+v; },0) / saldosPos.length)
      : 2000;
    var elAporte = document.getElementById('mil-aporte');
    if (elAporte) elAporte.value = mediaSaldo;

    // Presets de taxa
    document.querySelectorAll('.fin-preset-btn').forEach(function(btn) {
      btn.addEventListener('click', function() {
        document.querySelectorAll('.fin-preset-btn').forEach(function(b){ b.classList.remove('active'); });
        this.classList.add('active');
        var el = document.getElementById('mil-taxa');
        if (el) el.value = this.dataset.taxa;
        calcularMilhao();
      });
    });

    // Presets de meta
    document.querySelectorAll('.fin-meta-btn').forEach(function(btn) {
      btn.addEventListener('click', function() {
        document.querySelectorAll('.fin-meta-btn').forEach(function(b){ b.classList.remove('active'); });
        this.classList.add('active');
        metaMilhao = parseInt(this.dataset.meta);
        var badge = document.getElementById('mil-meta-badge');
        if (badge) badge.textContent = 'Meta: ' + fmt(metaMilhao);
        calcularMilhao();
      });
    });

    // Botão calcular
    var btnCalc = document.getElementById('mil-calc-btn');
    if (btnCalc) btnCalc.addEventListener('click', calcularMilhao);

    // Recalcular em tempo real ao mudar inputs
    ['mil-aporte','mil-patrimonio','mil-taxa'].forEach(function(id) {
      var el = document.getElementById(id);
      if (el) el.addEventListener('input', calcularMilhao);
    });

    // Calcular logo de cara
    calcularMilhao();
  }

  function calcularMilhao() {
    var aporte     = parseFloat(document.getElementById('mil-aporte')    ?.value) || 0;
    var patrimonio = parseFloat(document.getElementById('mil-patrimonio') ?.value) || 0;
    var taxa       = (parseFloat(document.getElementById('mil-taxa')      ?.value) || 1) / 100;
    var meta       = metaMilhao;

    // Data de nascimento: 05/04/2001
    var nascimento = new Date(2001, 3, 5); // April 5, 2001

    if (aporte <= 0 && patrimonio < meta) {
      return;
    }

    // Cálculo iterativo: FV = PV*(1+r)^n + PMT*((1+r)^n - 1)/r
    var n = 0, fv = patrimonio;
    var MAX = 12000; // 1000 anos max
    while (fv < meta && n < MAX) {
      fv = fv * (1 + taxa) + aporte;
      n++;
    }

    if (n >= MAX) {
      // Nunca vai atingir
      var elData  = document.getElementById('mil-data');
      var elIdade = document.getElementById('mil-idade');
      if (elData)  elData.textContent  = 'Nunca com este aporte';
      if (elIdade) elIdade.textContent = 'Aumente o aporte mensal';
      return;
    }

    // Data alvo
    var hoje       = new Date();
    var dataAlvo   = new Date(hoje);
    dataAlvo.setMonth(dataAlvo.getMonth() + n);

    // Idade na data alvo
    var diffMs    = dataAlvo - nascimento;
    var idadeTotal = diffMs / (1000 * 60 * 60 * 24 * 365.25);
    var anos      = Math.floor(idadeTotal);
    var mesesR    = Math.floor((idadeTotal - anos) * 12);

    // Total aportado vs juros
    var totalAportado = aporte * n + patrimonio;
    var jurosGerados  = fv - totalAportado;

    // Progresso atual
    var pct = Math.min((patrimonio / meta) * 100, 100);

    // Mostrar display
    var idle    = document.getElementById('mil-idle');
    var display = document.getElementById('mil-display');
    if (idle)    idle.classList.add('hidden');
    if (display) display.classList.remove('hidden');

    // Preencher valores
    var elData  = document.getElementById('mil-data');
    var elIdade = document.getElementById('mil-idade');
    var elMeses = document.getElementById('mil-meses');
    var elTotalA= document.getElementById('mil-total-aportado');
    var elJuros = document.getElementById('mil-juros');
    var elFill  = document.getElementById('mil-prog-fill');
    var elGlow  = document.getElementById('mil-prog-glow');
    var elPct   = document.getElementById('mil-prog-pct');
    var elAtual = document.getElementById('mil-prog-atual');
    var elMeta  = document.getElementById('mil-prog-meta');
    var badge   = document.getElementById('mil-meta-badge');

    var meses_str = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];
    var dataStr = ('0' + dataAlvo.getDate()).slice(-2) + '/' + meses_str[dataAlvo.getMonth()] + '/' + dataAlvo.getFullYear();

    if (badge)   badge.textContent = 'Meta: ' + fmt(meta);
    if (elData)  elData.textContent  = dataStr;
    if (elIdade) elIdade.textContent = anos + ' anos e ' + mesesR + ' meses';
    if (elMeses) elMeses.textContent = n + ' meses (' + Math.floor(n/12) + ' anos)';
    if (elTotalA) elTotalA.textContent = fmt(totalAportado);
    if (elJuros)  elJuros.textContent  = fmt(jurosGerados);
    if (elFill)   elFill.style.width   = pct + '%';
    if (elGlow)   elGlow.style.left    = pct + '%';
    if (elPct)    elPct.textContent    = pct.toFixed(1) + '% concluído';
    if (elAtual)  elAtual.textContent  = fmt(patrimonio);
    if (elMeta)   elMeta.textContent   = fmt(meta);

    // Mini gráfico de evolução
    renderMilhaoChart(n, aporte, patrimonio, taxa, meta);
  }

  function renderMilhaoChart(n, aporte, patrimonio, taxa, meta) {
    var canvas = document.getElementById('mil-chart-evolucao');
    if (!canvas || typeof Chart === 'undefined') return;

    // Gerar pontos a cada 12 meses
    var pontos = [], labels = [];
    var fv = patrimonio;
    var step = Math.max(1, Math.floor(n / 30)); // max 30 pontos
    for (var i = 0; i <= n; i++) {
      if (i % step === 0 || i === n) {
        labels.push('Mês ' + i);
        pontos.push(parseFloat(fv.toFixed(2)));
      }
      fv = fv * (1 + taxa) + aporte;
    }

    if (chartMilhao) chartMilhao.destroy();
    chartMilhao = new Chart(canvas, {
      type: 'line',
      data: {
        labels: labels,
        datasets: [{
          label: 'Patrimônio',
          data: pontos,
          borderColor: '#00e5ff',
          backgroundColor: 'rgba(0,229,255,0.08)',
          borderWidth: 2,
          pointRadius: 0,
          tension: 0.4,
          fill: true,
        },{
          label: 'Meta',
          data: Array(labels.length).fill(meta),
          borderColor: 'rgba(105,240,174,0.5)',
          borderWidth: 1,
          borderDash: [6,4],
          pointRadius: 0,
          fill: false,
        }]
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        plugins: {
          legend: { labels: { color: '#b0bec5', font: { family: 'Rajdhani', size: 11 }, boxWidth: 12 } },
          tooltip: { callbacks: { label: function(ctx){ return ' R$ '+ctx.raw.toLocaleString('pt-BR',{minimumFractionDigits:2}); } } }
        },
        scales: {
          x: { display: false },
          y: {
            ticks: { color: '#b0bec5', font: { family: 'Rajdhani', size: 11 }, callback: function(v){ return 'R$ '+(v/1000).toFixed(0)+'K'; } },
            grid: { color: 'rgba(0,229,255,0.06)' }
          }
        }
      }
    });
  }

  // ── ANÁLISE IA ─────────────────────────────────────────────────────────────
  function gerarAnaliseIA() {
    var result  = document.getElementById('fin-ai-result');
    var loading = document.getElementById('fin-ai-loading');
    var text    = document.getElementById('fin-ai-text');
    if (!result || !loading || !text) return;
    result.classList.remove('hidden');
    loading.classList.remove('hidden');
    text.classList.add('hidden');

    var kpis    = calcularKPIs(mesSelecionado, anoSelecionado);
    var kpisAnt = mesSelecionado > 1 ? calcularKPIs(mesSelecionado-1, anoSelecionado) : {receita:0,despesas:0,saldo:0};
    var payload = { mes: mesLabel(mesSelecionado, anoSelecionado), receita: kpis.receita, despesas: kpis.despesas, saldo: kpis.saldo, receita_ant: kpisAnt.receita, desp_ant: kpisAnt.despesas };

    fetch('/api/financeiro/analise', { method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify(payload) })
    .then(function(r){ return r.json(); })
    .then(function(data) {
      loading.classList.add('hidden');
      text.classList.remove('hidden');
      text.innerHTML = '<span class="fin-ai-jake">🤖 Jake diz:</span><br>' + (data.analise || 'Análise indisponível.');
    })
    .catch(function() {
      loading.classList.add('hidden');
      text.classList.remove('hidden');
      var difR = kpis.receita - kpisAnt.receita, difD = kpis.despesas - kpisAnt.despesas;
      text.innerHTML = '<span class="fin-ai-jake">🤖 Jake diz:</span><br>' + gerarAnaliseLocal(kpis, kpisAnt, difR, difD);
    });
  }

  function gerarAnaliseLocal(kpis, kpisAnt, difR, difD) {
    var partes = [];
    if (kpisAnt.receita > 0) {
      var varR = ((difR / kpisAnt.receita) * 100).toFixed(1);
      partes.push(difR > 0
        ? 'Suas receitas cresceram <strong>' + varR + '%</strong> em relação ao mês anterior — ótima evolução!'
        : difR < 0 ? 'Suas receitas recuaram <strong>' + Math.abs(varR) + '%</strong> vs. mês anterior. Reveja a entrada de novos projetos.'
        : 'Suas receitas se mantiveram estáveis.');
    }
    var tx = ((kpis.despesas / kpis.receita) * 100).toFixed(1);
    partes.push('Você comprometeu <strong>' + tx + '%</strong> da receita com despesas este mês.');
    partes.push(kpis.saldo >= 0
      ? 'Saldo positivo de <strong>' + fmt(kpis.saldo) + '</strong> — considere destinar parte para investimentos e reserva de emergência.'
      : 'Saldo negativo de <strong>' + fmt(Math.abs(kpis.saldo)) + '</strong> — revise despesas variáveis e parcelamentos.');
    return partes.join(' ');
  }

  // ── FORMULÁRIO ─────────────────────────────────────────────────────────────
  function adicionarLancamento() {
    var desc  = document.getElementById('fin-desc');
    var valor = document.getElementById('fin-valor');
    var data  = document.getElementById('fin-data');
    var tipo  = document.getElementById('fin-tipo');
    var cat   = document.getElementById('fin-categoria');
    var rec   = document.getElementById('fin-recorrente');
    if (!desc?.value.trim() || !valor?.value || !data?.value) { flash('Preencha Descrição, Valor e Data.','error'); return; }
    TRANSACOES.push({ id:_nextId++, descricao:desc.value.trim(), valor:parseFloat(valor.value), tipo:tipo.value, categoria:cat.value, recorrente:rec?.checked||false, data:data.value });
    desc.value = ''; valor.value = '';
    flash('Lançamento adicionado!','success');
    atualizarTudo();
  }

  function navegarMes(dir) {
    mesSelecionado += dir;
    if (mesSelecionado > 12) { mesSelecionado = 1;  anoSelecionado++; }
    if (mesSelecionado < 1)  { mesSelecionado = 12; anoSelecionado--; }
    atualizarTudo();
  }

  function atualizarMesLabel() {
    var el = document.getElementById('fin-mes-label');
    if (el) el.textContent = mesLabel(mesSelecionado, anoSelecionado);
  }

  function flash(msg, tipo) {
    var el = document.getElementById('fin-flash');
    if (!el) return;
    el.textContent = msg;
    el.className = 'fin-flash fin-flash-' + tipo;
    el.classList.remove('hidden');
    setTimeout(function(){ el.classList.add('hidden'); }, 3000);
  }

  // ── OBSERVER: inicializar quando a página for ativada ─────────────────────
  var _iniciado = false;
  var _observer = new MutationObserver(function(muts) {
    muts.forEach(function(m) {
      if (m.target.id === 'page-financeiro' && m.target.classList.contains('active')) {
        if (!_iniciado) { _iniciado = true; initFinanceiro(); }
        else { renderCharts(); renderRaioX(); }
      }
    });
  });
  var pageFin = document.getElementById('page-financeiro');
  if (pageFin) {
    _observer.observe(pageFin, { attributes: true, attributeFilter: ['class'] });
    if (pageFin.classList.contains('active')) { _iniciado = true; initFinanceiro(); }
  }

})();

