.sa-dropzone:hover,
.sa-dropzone.sa-dragover {
  border-color: var(--cyan);
  background: rgba(0,229,255,.05);
}

.sa-file-input {
  position: absolute;
  inset: 0;
  opacity: 0;
  cursor: pointer;
}

.sa-drop-placeholder {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: .3rem;
  color: rgba(176,190,197,.5);
  font-size: .8rem;
  pointer-events: none;
}

.sa-drop-placeholder span {
