.sa-preview-grid img {
  width: 100%;
  height: 52px;
  object-fit: cover;
  border-radius: 6px;
}

.sa-actions {
  display: grid;
  grid-template-columns: minmax(0,1fr) auto;
  gap: .6rem;
  margin-top: .25rem;
}

.sa-btn-primary {
  height: 44px;
  border-radius: 10px;
  border: none;
  background: linear-gradient(135deg, #00e5ff 0%, #00b8d4 40%, #006dd9 100%);
  color: #020d18;
  font-family: var(--ff-b);
  font-size: .95rem;
  font-weight: 700;
  letter-spacing: .06em;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: .55rem;
  box-shadow: 0 0 22px rgba(0,229,255,.38), 0 4px 16px rgba(0,0,0,.45);
  transition: opacity .2s, transform .15s, box-shadow .2s;
}

.sa-btn-primary:hover {
  opacity: .95;
  transform: translateY(-1px);
  box-shadow: 0 0 30px rgba(0,229,255,.55), 0 6px 20px rgba(0,0,0,.45);
}

.sa-btn-primary:disabled {
  opacity: .45;
  cursor: not-allowed;
  box-shadow: none;
  transform: none;
}

.sa-btn-icon {
  font-size: 1rem;
}

.sa-btn-ghost {
  height: 44px;
  border-radius: 10px;
  border: 1px solid rgba(176,190,197,.35);
  background: transparent;
  color: rgba(176,190,197,.8);
  font-family: var(--ff-b);
  font-size: .85rem;
  cursor: pointer;
  padding: 0 1rem;
  transition: color .2s, border-color .2s, background .2s;
}

.sa-btn-ghost:hover {
  border-color: var(--cyan);
  color: var(--cyan);
  background: rgba(0,229,255,.06);
}

.sa-status {
  margin-top: .25rem;
  font-size: .8rem;
  padding: .4rem .65rem;
  border-radius: 6px;
  display: none;
}

.sa-status.visible { display: block; }
.sa-status-ok { background: rgba(105,240,174,.12); color: var(--green); border: 1px solid rgba(105,240,174,.25); }
.sa-status-error { background: rgba(255,82,82,.12); color: var(--red); border: 1px solid rgba(255,82,82,.25); }
.sa-status-loading { background: rgba(0,229,255,.12); color: var(--cyan); border: 1px solid rgba(0,229,255,.25); }

.sa-main {
  display: flex;
  flex-direction: column;
  background: var(--bg);
}

.sa-toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 1rem 1.5rem .75rem;
  border-bottom: 1px solid var(--border);
  background: rgba(7,11,18,.96);
}

.sa-toolbar-label {
  font-family: var(--ff-h);
  font-size: .72rem;
  letter-spacing: .12em;
  text-transform: uppercase;
  color: rgba(176,190,197,.6);
}

.sa-toolbar-right {
  display: flex;
  align-items: center;
  gap: .6rem;
}

.sa-chip-toggle {
  padding: .3rem .7rem;
  border-radius: 999px;
  border: 1px solid rgba(0,229,255,.25);
  background: transparent;
  color: rgba(176,190,197,.7);
  font-size: .78rem;
  font-family: var(--ff-b);
  cursor: pointer;
  transition: all .2s;
}

.sa-chip-toggle.sa-active {
  background: rgba(0,229,255,.16);
  color: var(--cyan);
  border-color: var(--cyan);
  box-shadow: 0 0 12px rgba(0,229,255,.25);
}

.sa-btn-publish {
  padding: .4rem 1.2rem;
  border-radius: 999px;
  border: 1px solid rgba(0,229,255,.4);
  background: rgba(0,229,255,.08);
  color: var(--cyan);
  font-family: var(--ff-h);
  font-size: .8rem;
  letter-spacing: .12em;
  text-transform: uppercase;
  cursor: pointer;
  transition: all .2s;
}

.sa-btn-publish:hover {
  background: rgba(0,229,255,.18);
  box-shadow: 0 0 16px rgba(0,229,255,.35);
}

.sa-preview-area {
  flex: 1;
  min-height: 0;
  padding: 1rem 1.5rem .5rem;
  display: flex;
  flex-direction: column;
  gap: .75rem;
}

.sa-iframe {
  flex: 1;
  min-height: 0;
  width: 100%;
  border-radius: 12px;
  border: 1px solid var(--border);
  background: #0b101b;
}

.sa-html-view {
  flex: 1;
  min-height: 0;
  padding: 1rem 1.2rem;
  border-radius: 12px;
  border: 1px solid var(--border);
  background: #02030a;
  color: var(--white);
  font-family: "JetBrains Mono", monospace;
  font-size: .8rem;
  overflow: auto;
}

.sa-chat {
  border-top: 1px solid var(--border);
  padding: .75rem 1.5rem 1rem;
  background: rgba(7,11,18,.98);
}

.sa-chat-header {
  display: flex;
  flex-direction: column;
  gap: .2rem;
  margin-bottom: .5rem;
}

.sa-chat-title {
  font-family: var(--ff-h);
  font-size: .75rem;
  letter-spacing: .12em;
  text-transform: uppercase;
  color: rgba(176,190,197,.7);
}

.sa-chat-hint {
  font-size: .78rem;
  color: rgba(176,190,197,.45);
}

.sa-chat-body {
  max-height: 130px;
  overflow-y: auto;
  padding: .4rem 0 .6rem;
  display: flex;
  flex-direction: column;
  gap: .35rem;
  font-size: .86rem;
}

.sa-chat-msg {
  display: inline-flex;
  max-width: 100%;
  padding: .4rem .65rem;
  border-radius: 8px;
  font-size: .86rem;
}

.sa-chat-msg-user {
  align-self: flex-end;
  background: rgba(0,229,255,.16);
  color: var(--white);
}

.sa-chat-msg-ai {
  align-self: flex-start;
  background: rgba(255,255,255,.04);
  color: rgba(176,190,197,.9);
}

.sa-chat-form {
  display: grid;
  grid-template-columns: minmax(0,1fr) auto;
  gap: .5rem;
}

.sa-chat-input {
  background: rgba(255,255,255,.03);
  border-radius: 999px;
  border: 1px solid rgba(0,229,255,.2);
  padding: .55rem .9rem;
  color: var(--white);
  font-family: var(--ff-b);
  font-size: .9rem;
  outline: none;
}

.sa-chat-input:focus {
  border-color: var(--cyan);
  box-shadow: 0 0 0 2px rgba(0,229,255,.14);
}

.sa-chat-input::placeholder {
  color: rgba(176,190,197,.35);
}

.sa-chat-send {
  padding: .45rem 1.2rem;
  border-radius: 999px;
  border: 1px solid rgba(0,229,255,.4);
  background: rgba(0,229,255,.08);
  color: var(--cyan);
  font-family: var(--ff-b);
  font-size: .85rem;
  cursor: pointer;
  transition: all .2s;
}

.sa-chat-send:hover {
  background: rgba(0,229,255,.18);
}

@media (max-width: 960px) {
  .sa-layout {
    grid-template-columns: 1fr;
    grid-template-rows: auto 1fr;
    height: auto;
  }
  .sa-sidebar {
    max-height: 360px;
  }
}

