    var totalReceita = totais.receitas.reduce(function(s,v){ return s+v; }, 0);
    var totalDespesa = totais.fixas.reduce(function(s,v){ return s+v; }, 0) +
                       totais.variaveis.reduce(function(s,v){ return s+v; }, 0);
    var totalSaldo   = totalReceita - totalDespesa;
    var acumDez      = totais.acumulado[11];

    var elAcum = document.getElementById('fin-acum-dez');
    var elCR   = document.getElementById('fin-chip-receita');
    var elCD   = document.getElementById('fin-chip-despesa');
