        <button class="btn-view active" data-view="dia">Dia</button>
        <button class="btn-view" data-view="semana">Semana</button>
        <button class="btn-view" data-view="mes">Mês</button>
      </div>
      <!-- Navegação de período -->
      <div class="periodo-nav">
        <button onclick="navegarPeriodo(-1)">◀</button>
        <span id="agenda-periodo-label">Março 2026</span>
        <button onclick="navegarPeriodo(1)">▶</button>
        <button onclick="irParaHoje()">Hoje</button>
      </div>
      <!-- Ações rápidas -->
      <div class="agenda-acoes">
        <button class="btn-neon" onclick="abrirModalTarefa()">+ Tarefa</button>
        <button class="btn-outline" onclick="abrirModalRotina()">🔁 Rotina</button>
