        cur.execute("""
            INSERT INTO agenda_tarefas (titulo, descricao, categoria, data, hora_inicio, hora_fim, prioridade)
            VALUES (%s,%s,%s,%s,%s,%s,%s) RETURNING id
        """, (
            d.get("titulo","Sem título"), d.get("descricao"), d.get("categoria","geral"),
            d.get("data"), d.get("hora_inicio") or None, d.get("hora_fim") or None,
            d.get("prioridade","media")
        ))
        new_id = cur.fetchone()[0]
        conn.commit()
        cur.execute("SELECT * FROM agenda_tarefas WHERE id=%s", (new_id,))
        cols = [x[0] for x in cur.description]
        row  = _tarefa_to_dict(cur.fetchone(), cols)
        cur.close(); conn.close()
        return jsonify({"success": True, "data": row})
    except Exception as e:
        return jsonify({"success": False, "error": str(e)}), 500

