/* ─────────────────────────────────────────────────────
   Jake OS — Módulo Agenda
   Visões: Semana | Mês | Dia
───────────────────────────────────────────────────── */
(function () {

  var state = {
    view: 'semana',
    hoje: new Date(),
    dataAtual: new Date(),
    tarefas: [],
    rotinas: [],
    editandoId: null
  };

  var CORES = {
    trabalho:   '#00e5ff',
    pessoal:    '#ffd740',
    academia:   '#69f0ae',
    casa:       '#ce93d8',
    financeiro: '#ff9800',
    viagem:     '#4fc3f7',
    saude:      '#ff5252',
    lazer:      '#f48fb1',
    geral:      '#90a4ae'
  };

  var MESES = ['Janeiro','Fevereiro','Março','Abril','Maio','Junho',
               'Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];
  var DIAS_CURTOS = ['Dom','Seg','Ter','Qua','Qui','Sex','Sáb'];

  // ── UTILS ────────────────────────────────────────────────────────────────

  function isoData(d) {
    var mm = String(d.getMonth()+1).padStart(2,'0');
    var dd = String(d.getDate()).padStart(2,'0');
    return d.getFullYear() + '-' + mm + '-' + dd;
  }

  function isoMes(d) {
    return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0');
  }

  function addDias(d, n) {
    var r = new Date(d);
    r.setDate(r.getDate() + n);
    return r;
  }

  function inicioSemana(d) {
    var r = new Date(d);
    var dow = r.getDay(); // 0=dom
    var diff = dow === 0 ? -6 : 1 - dow; // começa na segunda
    r.setDate(r.getDate() + diff);
    return r;
  }

  function horaParaMinutos(h) {
    if (!h) return null;
    var p = h.split(':');
    return parseInt(p[0])*60 + parseInt(p[1]);
  }

  function rotinaAtivaNodia(rotina, data) {
    var dow = data.getDay(); // 0=dom
    var diaN = dow === 0 ? 7 : dow; // seg=1..dom=7
    var dias = rotina.dias_semana.split(',').map(Number);
    return dias.indexOf(diaN) !== -1;
  }

  function labelPeriodo() {
    if (state.view === 'mes') {
      return MESES[state.dataAtual.getMonth()] + ' ' + state.dataAtual.getFullYear();
    }
    if (state.view === 'dia') {
      var d = state.dataAtual;
      return DIAS_CURTOS[d.getDay()] + ', ' + d.getDate() + ' de ' + MESES[d.getMonth()];
    }
    // semana
    var seg = inicioSemana(state.dataAtual);
    var dom = addDias(seg, 6);
    if (seg.getMonth() === dom.getMonth()) {
      return seg.getDate() + ' – ' + dom.getDate() + ' de ' + MESES[seg.getMonth()] + ' ' + seg.getFullYear();
    }
    return seg.getDate() + '/' + (seg.getMonth()+1) + ' – ' + dom.getDate() + '/' + (dom.getMonth()+1) + ' ' + dom.getFullYear();
  }

  // ── API ──────────────────────────────────────────────────────────────────

  function apiGet(url) {
    return fetch(url).then(function(r){ return r.json(); });
  }

  function apiPost(url, body) {
    return fetch(url, { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify(body) }).then(function(r){ return r.json(); });
  }

  function apiPut(url, body) {
    return fetch(url, { method:'PUT', headers:{'Content-Type':'application/json'}, body: JSON.stringify(body) }).then(function(r){ return r.json(); });
  }

  function apiDelete(url) {
    return fetch(url, { method:'DELETE' }).then(function(r){ return r.json(); });
  }

  function apiPatch(url) {
    return fetch(url, { method:'PATCH' }).then(function(r){ return r.json(); });
  }

  function carregarDados(cb) {
    if (state.view === 'semana') {
      var seg = isoData(inicioSemana(state.dataAtual));
      apiGet('/api/agenda/semana?inicio=' + seg).then(function(res) {
        if (res.success) { state.tarefas = res.tarefas; state.rotinas = res.rotinas; }
        if (cb) cb();
      });
    } else if (state.view === 'mes') {
      var mes = isoMes(state.dataAtual);
      Promise.all([
        apiGet('/api/agenda/tarefas?mes=' + mes),
        apiGet('/api/agenda/rotinas')
      ]).then(function(rs) {
        if (rs[0].success) state.tarefas = rs[0].data;
        if (rs[1].success) state.rotinas = rs[1].data;
        if (cb) cb();
      });
    } else { // dia
      var data = isoData(state.dataAtual);
      Promise.all([
        apiGet('/api/agenda/tarefas?data=' + data),
        apiGet('/api/agenda/rotinas')
      ]).then(function(rs) {
        if (rs[0].success) state.tarefas = rs[0].data;
        if (rs[1].success) state.rotinas = rs[1].data;
        if (cb) cb();
      });
    }
  }

  // ── RENDER SEMANA ────────────────────────────────────────────────────────

  function renderSemana() {
    var seg = inicioSemana(state.dataAtual);
    var hoje = isoData(state.hoje);
    var HORAS_INICIO = 6, HORAS_FIM = 23;
    var H = 60; // px por hora

    var html = '<div class="ag-semana-wrap">';
    // Header
    html += '<div class="ag-semana-header"><div class="ag-hora-col"></div>';
    for (var i = 0; i < 7; i++) {
      var d = addDias(seg, i);
      var iso = isoData(d);
      var isHoje = iso === hoje;
      html += '<div class="ag-semana-col-hdr' + (isHoje ? ' ag-hoje' : '') + '">' +
        DIAS_CURTOS[d.getDay()] + '<span class="ag-dia-num">' + d.getDate() + '</span></div>';
    }
    html += '</div>'; // end header

    // Tarefas sem hora (topo)
    html += '<div class="ag-semana-allday"><div class="ag-hora-col" style="font-size:10px;color:#546e7a;padding:4px 6px;">dia todo</div>';
    for (var i = 0; i < 7; i++) {
      var d = addDias(seg, i);
      var iso = isoData(d);
      var semHora = state.tarefas.filter(function(t){ return t.data === iso && !t.hora_inicio; });
      html += '<div class="ag-allday-col">';
      semHora.forEach(function(t) {
        var cor = CORES[t.categoria] || CORES.geral;
        html += '<div class="ag-pill' + (t.concluida ? ' ag-concluida' : '') + '" style="background:' + cor + '" data-id="' + t.id + '">' + t.titulo + '</div>';
      });
      html += '</div>';
    }
    html += '</div>';

    // Grid de horas
    html += '<div class="ag-semana-body"><div class="ag-semana-horas">';
    for (var h = HORAS_INICIO; h <= HORAS_FIM; h++) {
      html += '<div class="ag-hora-label">' + String(h).padStart(2,'0') + ':00</div>';
    }
    html += '</div><div class="ag-semana-cols">';

    for (var i = 0; i < 7; i++) {
      var d = addDias(seg, i);
      var iso = isoData(d);
      var isHoje = iso === hoje;
      html += '<div class="ag-semana-col' + (isHoje ? ' ag-col-hoje' : '') + '" data-data="' + iso + '">';

      // Slots clicáveis
      for (var h = HORAS_INICIO; h <= HORAS_FIM; h++) {
        var hStr = String(h).padStart(2,'0') + ':00';
        html += '<div class="ag-hora-slot" data-data="' + iso + '" data-hora="' + hStr + '"></div>';
      }

      // Rotinas
      state.rotinas.forEach(function(rot) {
        if (!rotinaAtivaNodia(rot, d)) return;
        var hi = horaParaMinutos(rot.hora_inicio);
        var hf = rot.hora_fim ? horaParaMinutos(rot.hora_fim) : hi + 60;
        if (hi === null || hi < HORAS_INICIO*60 || hi >= HORAS_FIM*60) return;
        var top = (hi - HORAS_INICIO*60) / 60 * H;
        var height = Math.max(20, (hf - hi) / 60 * H);
        var cor = CORES[rot.categoria] || CORES.geral;
        html += '<div class="ag-bloco ag-bloco-rotina" style="top:' + top + 'px;height:' + height + 'px;background:' + cor + '22;border-left:3px solid ' + cor + '" title="' + rot.titulo + '">' +
          '<span style="color:' + cor + '">' + rot.hora_inicio + '</span> ' + rot.titulo + '</div>';
      });

      // Tarefas com hora
      state.tarefas.filter(function(t){ return t.data === iso && t.hora_inicio; }).forEach(function(t) {
        var hi = horaParaMinutos(t.hora_inicio);
        var hf = t.hora_fim ? horaParaMinutos(t.hora_fim) : hi + 60;
        if (hi < HORAS_INICIO*60 || hi >= HORAS_FIM*60) return;
        var top = (hi - HORAS_INICIO*60) / 60 * H;
        var height = Math.max(24, (hf - hi) / 60 * H);
        var cor = CORES[t.categoria] || CORES.geral;
        html += '<div class="ag-bloco' + (t.concluida ? ' ag-concluida' : '') + '" style="top:' + top + 'px;height:' + height + 'px;background:' + cor + ';color:#050810" data-id="' + t.id + '">' +
          '<strong>' + t.hora_inicio + '</strong> ' + t.titulo + '</div>';
      });

      html += '</div>'; // col
    }
    html += '</div></div></div>'; // cols, body, wrap

    document.getElementById('agenda-container').innerHTML = html;
    bindSemanaEvents();

    // Linha do agora
    atualizarLinhaAgora();
  }

  function atualizarLinhaAgora() {
    document.querySelectorAll('.ag-linha-agora').forEach(function(el){ el.remove(); });
    var agora = new Date();
    var seg = inicioSemana(state.dataAtual);
    var isoHoje = isoData(agora);
    for (var i = 0; i < 7; i++) {
      var d = addDias(seg, i);
      if (isoData(d) !== isoHoje) continue;
      var HORAS_INICIO = 6, H = 60;
      var min = agora.getHours()*60 + agora.getMinutes();
      var top = (min - HORAS_INICIO*60) / 60 * H;
      if (top < 0) return;
      var cols = document.querySelectorAll('.ag-semana-col');
      if (cols[i]) {
        var linha = document.createElement('div');
        linha.className = 'ag-linha-agora';
        linha.style.top = top + 'px';
        cols[i].appendChild(linha);
      }
    }
  }

  function bindSemanaEvents() {
    document.querySelectorAll('.ag-hora-slot').forEach(function(el) {
      el.addEventListener('click', function() {
        abrirModalTarefa(this.dataset.data, this.dataset.hora);
      });
    });
    document.querySelectorAll('.ag-bloco[data-id]').forEach(function(el) {
      el.addEventListener('click', function(e) {
        e.stopPropagation();
        var t = state.tarefas.find(function(x){ return x.id == el.dataset.id; });
        if (t) abrirModalTarefa(t.data, t.hora_inicio, t);
      });
    });
    document.querySelectorAll('.ag-pill[data-id]').forEach(function(el) {
      el.addEventListener('click', function(e) {
        e.stopPropagation();
        var t = state.tarefas.find(function(x){ return x.id == el.dataset.id; });
        if (t) abrirModalTarefa(t.data, null, t);
      });
    });
  }

  // ── RENDER MÊS ───────────────────────────────────────────────────────────

  function renderMes() {
    var ano = state.dataAtual.getFullYear();
    var mes = state.dataAtual.getMonth();
    var hoje = isoData(state.hoje);
    var primeiroDia = new Date(ano, mes, 1);
    var ultimoDia = new Date(ano, mes+1, 0);
    var dow = primeiroDia.getDay(); // 0=dom
    var inicioCal = addDias(primeiroDia, dow === 0 ? -6 : 1 - dow);

    var html = '<div class="ag-mes-grid">';
    ['Seg','Ter','Qua','Qui','Sex','Sáb','Dom'].forEach(function(d){
      html += '<div class="ag-mes-hdr">' + d + '</div>';
    });

    for (var row = 0; row < 6; row++) {
      for (var col = 0; col < 7; col++) {
        var d = addDias(inicioCal, row*7 + col);
        var iso = isoData(d);
        var outroMes = d.getMonth() !== mes;
        var isHoje = iso === hoje;
        var tarefasDia = state.tarefas.filter(function(t){ return t.data === iso; });
        var rotinasDia = state.rotinas.filter(function(r){ return rotinaAtivaNodia(r, d); });
        var eventos = rotinasDia.map(function(r){ return {titulo: r.titulo, categoria: r.categoria, rotina: true}; })
                      .concat(tarefasDia.map(function(t){ return {titulo: t.titulo, categoria: t.categoria, concluida: t.concluida}; }));

        html += '<div class="ag-mes-cel' + (outroMes ? ' ag-outro-mes' : '') + (isHoje ? ' ag-hoje-cel' : '') + '" data-data="' + iso + '">';
        html += '<div class="ag-mes-num">' + d.getDate() + '</div>';
        var visiveis = eventos.slice(0, 3);
        visiveis.forEach(function(ev) {
          var cor = CORES[ev.categoria] || CORES.geral;
          html += '<div class="ag-mes-pill' + (ev.rotina ? ' ag-mes-pill-rotina' : '') + (ev.concluida ? ' ag-concluida' : '') + '" style="background:' + cor + '">' + ev.titulo + '</div>';
        });
        if (eventos.length > 3) html += '<div class="ag-mes-mais">+' + (eventos.length-3) + ' mais</div>';
        html += '</div>';
      }
    }
    html += '</div>';
    document.getElementById('agenda-container').innerHTML = html;
    document.getElementById('agenda-day-panel').classList.add('hidden');
    bindMesEvents();
  }

  function bindMesEvents() {
    document.querySelectorAll('.ag-mes-cel').forEach(function(el) {
      el.addEventListener('click', function() {
        var iso = this.dataset.data;
        var d = new Date(iso + 'T00:00:00');
        state.dataAtual = d;
        mostrarDayPanel(iso);
      });
    });
  }

  function mostrarDayPanel(iso) {
    var panel = document.getElementById('agenda-day-panel');
    var d = new Date(iso + 'T00:00:00');
    var tarefas = state.tarefas.filter(function(t){ return t.data === iso; });
    var rotinas = state.rotinas.filter(function(r){ return rotinaAtivaNodia(r, d); });

    var html = '<div class="ag-panel-header">' +
      '<span>' + d.getDate() + ' de ' + MESES[d.getMonth()] + '</span>' +
      '<button class="btn-neon-ag ag-btn-sm" onclick="window._agAbrirTarefa(\'' + iso + '\')">+ Tarefa</button>' +
      '</div>';

    if (rotinas.length) {
      html += '<div class="ag-panel-section">🔁 Rotinas</div>';
      rotinas.forEach(function(r) {
        var cor = CORES[r.categoria] || CORES.geral;
        html += '<div class="ag-tarefa-item ag-rotina-item">' +
          '<span class="ag-cat-dot" style="background:' + cor + '"></span>' +
          '<span class="ag-tarefa-titulo">' + r.titulo + '</span>' +
          '<span class="ag-tarefa-hora">' + r.hora_inicio + (r.hora_fim ? '–'+r.hora_fim : '') + '</span>' +
          '</div>';
      });
    }

    if (tarefas.length) {
      html += '<div class="ag-panel-section">📌 Tarefas</div>';
      tarefas.forEach(function(t) {
        var cor = CORES[t.categoria] || CORES.geral;
        html += renderTarefaItem(t, cor);
      });
    }

    if (!rotinas.length && !tarefas.length) {
      html += '<div class="ag-empty">Nenhum evento neste dia. Clique em + Tarefa para adicionar.</div>';
    }

    panel.innerHTML = html;
    panel.classList.remove('hidden');
    bindTarefaItemEvents(panel);
  }

  // ── RENDER DIA ───────────────────────────────────────────────────────────

  function renderDia() {
    var iso = isoData(state.dataAtual);
    var hoje = isoData(state.hoje);
    var HORAS_INICIO = 6, HORAS_FIM = 23, H = 64;

    var html = '<div class="ag-dia-wrap">';

    // Tarefas sem hora
    var semHora = state.tarefas.filter(function(t){ return !t.hora_inicio; });
    if (semHora.length) {
      html += '<div class="ag-dia-allday">';
      semHora.forEach(function(t) {
        var cor = CORES[t.categoria] || CORES.geral;
        html += '<div class="ag-pill' + (t.concluida ? ' ag-concluida' : '') + '" style="background:' + cor + '" data-id="' + t.id + '">' + t.titulo + '</div>';
      });
      html += '</div>';
    }

    html += '<div class="ag-dia-timeline">';
    for (var h = HORAS_INICIO; h <= HORAS_FIM; h++) {
      var hStr = String(h).padStart(2,'0') + ':00';
      html += '<div class="ag-dia-row"><div class="ag-hora-label-dia">' + hStr + '</div>' +
        '<div class="ag-dia-slot" data-data="' + iso + '" data-hora="' + hStr + '"></div></div>';
    }

    // Rotinas
    state.rotinas.forEach(function(rot) {
      if (!rotinaAtivaNodia(rot, state.dataAtual)) return;
      var hi = horaParaMinutos(rot.hora_inicio);
      var hf = rot.hora_fim ? horaParaMinutos(rot.hora_fim) : hi + 60;
      if (hi === null || hi < HORAS_INICIO*60) return;
      var top = (hi - HORAS_INICIO*60) / 60 * H + 1;
      var height = Math.max(24, (hf - hi) / 60 * H - 2);
      var cor = CORES[rot.categoria] || CORES.geral;
      html += '<div class="ag-dia-bloco ag-bloco-rotina" style="top:' + top + 'px;height:' + height + 'px;left:60px;right:8px;background:' + cor + '22;border-left:3px solid ' + cor + '">' +
        '<span style="color:' + cor + ';font-size:10px">' + rot.hora_inicio + '</span> ' + rot.titulo + '</div>';
    });

    // Tarefas com hora
    state.tarefas.filter(function(t){ return t.hora_inicio; }).forEach(function(t) {
      var hi = horaParaMinutos(t.hora_inicio);
      var hf = t.hora_fim ? horaParaMinutos(t.hora_fim) : hi + 60;
      if (hi < HORAS_INICIO*60) return;
      var top = (hi - HORAS_INICIO*60) / 60 * H + 1;
      var height = Math.max(28, (hf - hi) / 60 * H - 2);
      var cor = CORES[t.categoria] || CORES.geral;
      html += '<div class="ag-dia-bloco' + (t.concluida ? ' ag-concluida' : '') + '" style="top:' + top + 'px;height:' + height + 'px;left:60px;right:8px;background:' + cor + ';color:#050810" data-id="' + t.id + '">' +
        '<strong>' + t.hora_inicio + '</strong> ' + t.titulo + '</div>';
    });

    // Linha do agora
    if (iso === hoje) {
      var agora = new Date();
      var min = agora.getHours()*60 + agora.getMinutes();
      var top = (min - HORAS_INICIO*60) / 60 * H;
      if (top >= 0) html += '<div class="ag-linha-agora-dia" style="top:' + top + 'px"></div>';
    }

    html += '</div></div>';
    document.getElementById('agenda-container').innerHTML = html;
    document.getElementById('agenda-day-panel').classList.add('hidden');
    bindDiaEvents();
  }

  function bindDiaEvents() {
    document.querySelectorAll('.ag-dia-slot').forEach(function(el) {
      el.addEventListener('click', function() {
        abrirModalTarefa(this.dataset.data, this.dataset.hora);
      });
    });
    document.querySelectorAll('.ag-dia-bloco[data-id]').forEach(function(el) {
      el.addEventListener('click', function(e) {
        e.stopPropagation();
        var t = state.tarefas.find(function(x){ return x.id == el.dataset.id; });
        if (t) abrirModalTarefa(t.data, t.hora_inicio, t);
      });
    });
  }

  // ── RENDER TAREFA ITEM ────────────────────────────────────────────────────

  function renderTarefaItem(t, cor) {
    var prCls = 'ag-pr-' + t.prioridade;
    return '<div class="ag-tarefa-item' + (t.concluida ? ' ag-concluida' : '') + '" data-id="' + t.id + '">' +
      '<div class="ag-check' + (t.concluida ? ' ag-checked' : '') + '" data-id="' + t.id + '">' + (t.concluida ? '✓' : '') + '</div>' +
      '<span class="ag-cat-dot" style="background:' + (cor||CORES.geral) + '"></span>' +
      '<div class="ag-tarefa-info">' +
        '<div class="ag-tarefa-titulo">' + t.titulo + '</div>' +
        (t.hora_inicio ? '<div class="ag-tarefa-hora">' + t.hora_inicio + (t.hora_fim ? '–'+t.hora_fim:'') + '</div>' : '') +
      '</div>' +
      '<div class="ag-pr-dot ' + prCls + '"></div>' +
      '<div class="ag-del-btn" data-id="' + t.id + '">✕</div>' +
      '</div>';
  }

  function bindTarefaItemEvents(container) {
    container.querySelectorAll('.ag-check').forEach(function(el) {
      el.addEventListener('click', function(e) {
        e.stopPropagation();
        var id = parseInt(this.dataset.id);
        apiPatch('/api/agenda/tarefas/' + id + '/concluir').then(function() {
          var t = state.tarefas.find(function(x){ return x.id === id; });
          if (t) t.concluida = !t.concluida;
          render();
        });
      });
    });
    container.querySelectorAll('.ag-del-btn').forEach(function(el) {
      el.addEventListener('click', function(e) {
        e.stopPropagation();
        var id = parseInt(this.dataset.id);
        apiDelete('/api/agenda/tarefas/' + id).then(function() {
          state.tarefas = state.tarefas.filter(function(x){ return x.id !== id; });
          render();
        });
      });
    });
    container.querySelectorAll('.ag-tarefa-item').forEach(function(el) {
      el.addEventListener('click', function() {
        var id = parseInt(this.dataset.id);
        var t = state.tarefas.find(function(x){ return x.id === id; });
        if (t) abrirModalTarefa(t.data, t.hora_inicio, t);
      });
    });
  }

  // ── RENDER PRINCIPAL ─────────────────────────────────────────────────────

  function render() {
    document.getElementById('ag-periodo-label').textContent = labelPeriodo();
    if (state.view === 'semana') renderSemana();
    else if (state.view === 'mes') renderMes();
    else renderDia();
  }

  function recarregarERender() {
    carregarDados(render);
  }

  // ── MODAIS ───────────────────────────────────────────────────────────────

  function abrirModalTarefa(data, hora, tarefa) {
    state.editandoId = tarefa ? tarefa.id : null;
    var modal = document.getElementById('modal-ag-tarefa');
    document.getElementById('ag-modal-tarefa-title').textContent = tarefa ? 'Editar Tarefa' : 'Nova Tarefa';
    document.getElementById('ag-tarefa-titulo').value   = tarefa ? tarefa.titulo : '';
    document.getElementById('ag-tarefa-descricao').value = tarefa ? (tarefa.descricao||'') : '';
    document.getElementById('ag-tarefa-categoria').value = tarefa ? tarefa.categoria : 'geral';
    document.getElementById('ag-tarefa-prioridade').value = tarefa ? tarefa.prioridade : 'media';
    document.getElementById('ag-tarefa-data').value     = data || isoData(state.dataAtual);
    document.getElementById('ag-tarefa-hi').value       = (tarefa ? tarefa.hora_inicio : hora) || '';
    document.getElementById('ag-tarefa-hf').value       = (tarefa ? tarefa.hora_fim : '') || '';
    modal.classList.remove('hidden');
    document.getElementById('ag-tarefa-titulo').focus();
  }

  window._agAbrirTarefa = function(data) { abrirModalTarefa(data); };

  function fecharModalTarefa() {
    document.getElementById('modal-ag-tarefa').classList.add('hidden');
    state.editandoId = null;
  }

  function salvarTarefa() {
    var titulo = document.getElementById('ag-tarefa-titulo').value.trim();
    if (!titulo) { document.getElementById('ag-tarefa-titulo').focus(); return; }
    var body = {
      titulo:      titulo,
      descricao:   document.getElementById('ag-tarefa-descricao').value.trim(),
      categoria:   document.getElementById('ag-tarefa-categoria').value,
      prioridade:  document.getElementById('ag-tarefa-prioridade').value,
      data:        document.getElementById('ag-tarefa-data').value,
      hora_inicio: document.getElementById('ag-tarefa-hi').value || null,
      hora_fim:    document.getElementById('ag-tarefa-hf').value || null,
    };
    var req = state.editandoId
      ? apiPut('/api/agenda/tarefas/' + state.editandoId, body)
      : apiPost('/api/agenda/tarefas', body);
    req.then(function(res) {
      if (res.success) {
        fecharModalTarefa();
        recarregarERender();
      }
    });
  }

  function abrirModalRotina() {
    document.getElementById('modal-ag-rotina').classList.remove('hidden');
    document.querySelectorAll('#ag-dias-selector .dia-btn').forEach(function(b){ b.classList.remove('ativo'); });
    document.getElementById('ag-rotina-titulo').value = '';
    document.getElementById('ag-rotina-hi').value = '';
    document.getElementById('ag-rotina-hf').value = '';
    document.getElementById('ag-rotina-titulo').focus();
  }

  function fecharModalRotina() {
    document.getElementById('modal-ag-rotina').classList.add('hidden');
  }

  function salvarRotina() {
    var titulo = document.getElementById('ag-rotina-titulo').value.trim();
    var hi     = document.getElementById('ag-rotina-hi').value;
    if (!titulo || !hi) return;
    var dias = [];
    document.querySelectorAll('#ag-dias-selector .dia-btn.ativo').forEach(function(b){ dias.push(b.dataset.dia); });
    if (!dias.length) { alert('Selecione ao menos um dia da semana.'); return; }
    var body = {
      titulo:      titulo,
      categoria:   document.getElementById('ag-rotina-categoria').value,
      hora_inicio: hi,
      hora_fim:    document.getElementById('ag-rotina-hf').value || null,
      dias_semana: dias.join(','),
      cor:         CORES[document.getElementById('ag-rotina-categoria').value] || '#00e5ff'
    };
    apiPost('/api/agenda/rotinas', body).then(function(res) {
      if (res.success) { fecharModalRotina(); recarregarERender(); }
    });
  }

  // ── INIT ─────────────────────────────────────────────────────────────────

  function initAgenda() {
    // View toggle
    document.querySelectorAll('.btn-view').forEach(function(btn) {
      btn.addEventListener('click', function() {
        document.querySelectorAll('.btn-view').forEach(function(b){ b.classList.remove('active'); });
        this.classList.add('active');
        state.view = this.dataset.view;
        recarregarERender();
      });
    });

    // Navegação
    document.getElementById('ag-prev').addEventListener('click', function() {
      if (state.view === 'mes') state.dataAtual.setMonth(state.dataAtual.getMonth()-1);
      else if (state.view === 'dia') state.dataAtual = addDias(state.dataAtual, -1);
      else state.dataAtual = addDias(state.dataAtual, -7);
      recarregarERender();
    });
    document.getElementById('ag-next').addEventListener('click', function() {
      if (state.view === 'mes') state.dataAtual.setMonth(state.dataAtual.getMonth()+1);
      else if (state.view === 'dia') state.dataAtual = addDias(state.dataAtual, 1);
      else state.dataAtual = addDias(state.dataAtual, 7);
      recarregarERender();
    });
    document.getElementById('ag-hoje').addEventListener('click', function() {
      state.dataAtual = new Date(state.hoje);
      recarregarERender();
    });

    // Botões de nova tarefa/rotina
    document.getElementById('ag-btn-tarefa').addEventListener('click', function() {
      abrirModalTarefa();
    });
    document.getElementById('ag-btn-rotina').addEventListener('click', abrirModalRotina);

    // Modal tarefa
    document.getElementById('ag-salvar-tarefa').addEventListener('click', salvarTarefa);
    document.getElementById('ag-cancelar-tarefa').addEventListener('click', fecharModalTarefa);

    // Modal rotina
    document.getElementById('ag-salvar-rotina').addEventListener('click', salvarRotina);
    document.getElementById('ag-cancelar-rotina').addEventListener('click', fecharModalRotina);

    // Dias da semana (modal rotina)
    document.querySelectorAll('#ag-dias-selector .dia-btn').forEach(function(btn) {
      btn.addEventListener('click', function() { this.classList.toggle('ativo'); });
    });

    // Fechar modal com Escape
    document.addEventListener('keydown', function(e) {
      if (e.key === 'Escape') { fecharModalTarefa(); fecharModalRotina(); }
    });

    // Atualiza linha do agora a cada minuto
    setInterval(atualizarLinhaAgora, 60000);

    recarregarERender();
  }

  // ── OBSERVER ─────────────────────────────────────────────────────────────
  var _iniciado = false;
  var obs = new MutationObserver(function(muts) {
    muts.forEach(function(m) {
      if (m.target.id === 'page-agenda' && m.target.classList.contains('active')) {
        if (!_iniciado) { _iniciado = true; initAgenda(); }
        else recarregarERender();
      }
    });
  });
  var pageAg = document.getElementById('page-agenda');
  if (pageAg) {
    obs.observe(pageAg, { attributes: true, attributeFilter: ['class'] });
    if (pageAg.classList.contains('active')) { _iniciado = true; initAgenda(); }
  }

})();

