def _get_db():
    import psycopg2
    db_url = os.environ.get("DATABASE_URL", "")
    return psycopg2.connect(db_url)

def _init_agenda_tables():
    try:
        conn = _get_db()
        cur = conn.cursor()
        cur.execute("""
            CREATE TABLE IF NOT EXISTS agenda_tarefas (
                id SERIAL PRIMARY KEY,
                titulo VARCHAR(200) NOT NULL,
                descricao TEXT,
                categoria VARCHAR(50) NOT NULL DEFAULT 'geral',
                data DATE NOT NULL,
                hora_inicio TIME,
                hora_fim TIME,
                concluida BOOLEAN DEFAULT FALSE,
                prioridade VARCHAR(20) DEFAULT 'media',
                criado_em TIMESTAMP DEFAULT NOW()
            )
        """)
        cur.execute("""
            CREATE TABLE IF NOT EXISTS agenda_rotinas (
                id SERIAL PRIMARY KEY,
                titulo VARCHAR(200) NOT NULL,
                categoria VARCHAR(50) NOT NULL DEFAULT 'geral',
                hora_inicio TIME NOT NULL,
                hora_fim TIME,
                dias_semana VARCHAR(20) NOT NULL,
                ativa BOOLEAN DEFAULT TRUE,
                cor VARCHAR(7) DEFAULT '#00e5ff',
                criado_em TIMESTAMP DEFAULT NOW()
            )
        """)
        conn.commit(); cur.close(); conn.close()
    except Exception as e:
        print(f"[Agenda] Erro ao criar tabelas: {e}")

_init_agenda_tables()

def _tarefa_to_dict(row, cols):
    d = dict(zip(cols, row))
    if d.get('data'): d['data'] = d['data'].isoformat()
    for k in ['hora_inicio','hora_fim']:
        if d.get(k): d[k] = str(d[k])[:5]
    if d.get('criado_em'): d['criado_em'] = d['criado_em'].isoformat()
    d['concluida'] = bool(d.get('concluida'))
    return d

def _rotina_to_dict(row, cols):
    d = dict(zip(cols, row))
    for k in ['hora_inicio','hora_fim']:
        if d.get(k): d[k] = str(d[k])[:5]
    if d.get('criado_em'): d['criado_em'] = d['criado_em'].isoformat()
    d['ativa'] = bool(d.get('ativa'))
    return d

